// Elektrik test bankasını kardeş fizik derslerinin standardına (270) tamamlar.
// Mevcut: 8/5 · 10/7 · 12/8 = 50 → Hedef: 30/30 · 45/45 · 60/60 = 270.
// Elle yazılmış, müfredat-hizalı, tekrarsız sorular. topup_mak.js deseni.
const vm = require("vm"), fs = require("fs"), path = require("path");
const BQ = path.resolve(__dirname, "..");
function load(f) { const c = {}; c.globalThis = c; vm.createContext(c); vm.runInContext(fs.readFileSync(path.join(BQ, f), "utf8"), c); return c.__BQ; }
const t = load("elektrik_test.js");
const S = (title, a, d) => [{ t: title, a, d }];

